package sn.gestionimmobiliere.backend.identity.application;
import java.time.Clock;import java.util.UUID;import org.springframework.boot.CommandLineRunner;import org.springframework.security.crypto.password.PasswordEncoder;import org.springframework.stereotype.Component;import sn.gestionimmobiliere.backend.identity.domain.*;import sn.gestionimmobiliere.backend.identity.infrastructure.AppUserRepository;import sn.gestionimmobiliere.backend.owner.application.OwnerProperties;
@Component public class BootstrapAdmin implements CommandLineRunner{private final AppUserRepository users;private final PasswordEncoder encoder;private final SecurityProperties security;private final OwnerProperties owner;private final Clock clock;public BootstrapAdmin(AppUserRepository u,PasswordEncoder e,SecurityProperties s,OwnerProperties o,Clock c){users=u;encoder=e;security=s;owner=o;clock=c;}public void run(String...args){if(!users.existsByEmailIgnoreCase(security.bootstrapEmail()))users.save(new AppUser(UUID.randomUUID(),owner.organizationId(),security.bootstrapEmail().toLowerCase(),encoder.encode(security.bootstrapPassword()),"Administrateur Demo",UserRole.ADMIN,clock.instant()));}}
